#include <bits/stdc++.h>
using namespace std;
int main(){
    long long n,b;
    scanf("%lld%lld",&n,&b);
    long long a[n+1];
    for(int i=1;i<=n;i++){
        scanf("%lld",&a[i]);
    }
    long long x,r,l,mix;
    for(int i=1;i<=b;i++){
        scanf("%lld",&x);
        l=1;
        r=n;
        while(r>=l){
            mix=(l+r)/2;
            if(a[mix]==x){
                printf("%lld\n",mix);
                break;
            }
            else if(a[mix]<x){
                l=mix+1;
            }
            else {
                r=mix-1;
            }
        }
        if(r<l){
            printf("%d\n",-1);
        }
    }
    return 0;
}
